//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Property-change revisions: rPrChange, pPrChange, sectPrChange
//! (reject-restore snapshot semantics)".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 about property-change revisions. A FAILING
//! assertion here is NOT a flaky test to silence: it encodes a real
//! Word-compliance gap in the stemma engine (divergence from how Microsoft
//! Word reads, accepts/rejects, or round-trips property-change revisions).
//! Fix the engine at the source, never weaken the test.
//!
//! Methodology (consumption vs. save):
//! - `reserialize()` of an UNEDITED doc reflects stemma's verbatim-preservation
//!   contract, NOT Word normalization. xmlContains / "xmlRegex" (ordering)
//!   checks on it are valid only for markup the serializer actively generates,
//!   orders, or restructures, and for opens-clean validity.
//! - Word consumption semantics ("reject restores prior") are asserted on the
//!   READ side: read_accepted()/read_rejected().to_text().

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: DOCX zip plumbing (mirrors the shared spec-suite prelude) ───

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document><w:body>…</w:body></w:document>` (the specs supply their own
/// trailing `<w:sectPr/>`). `extra_parts` are additional `(part_path, xml)`
/// entries (e.g. `("word/styles.xml", "…")`) for which a `[Content_Types].xml`
/// override is synthesized.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#,
    );

    fn override_for(part: &str) -> Option<&'static str> {
        if part.ends_with("styles.xml") {
            Some("application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml")
        } else if part.ends_with("numbering.xml") {
            Some("application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml")
        } else {
            None
        }
    }

    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let part_name = if part.starts_with('/') {
            part.to_string()
        } else {
            format!("/{part}")
        };
        let ct = override_for(part).unwrap_or_else(|| {
            panic!("make_docx: no content-type override known for extra part {part}")
        });
        overrides.push_str(&format!(
            r#"<Override PartName="{part_name}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize(default) → return the re-serialized `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Collapse whitespace that sits BETWEEN tags (`>   <` → `><`) and normalize
/// self-closing spacing, so an ordered-`contains` check can stand in for an
/// `\s*` ordering regex (the `regex` crate is not a dev-dependency here).
fn norm_xml(xml: &str) -> String {
    let mut out = String::with_capacity(xml.len());
    let bytes = xml.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let c = bytes[i] as char;
        if c == '>' {
            out.push('>');
            let mut j = i + 1;
            while j < bytes.len() && (bytes[j] as char).is_whitespace() {
                j += 1;
            }
            i = j;
            continue;
        }
        out.push(c);
        i += 1;
    }
    out.replace(" />", "/>").replace("/ >", "/>")
}

/// Ordered-subsequence check on normalized XML: every needle appears, in order.
fn contains_in_order(haystack_norm: &str, needles: &[&str]) -> Result<(), String> {
    let mut from = 0usize;
    for (idx, n) in needles.iter().enumerate() {
        match haystack_norm[from..].find(n) {
            Some(rel) => from += rel + n.len(),
            None => {
                return Err(format!(
                    "missing (in order) {:?}; matched prefix {:?}",
                    n,
                    &needles[..idx]
                ));
            }
        }
    }
    Ok(())
}

fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = stemma::api::validate(bytes);
    assert!(report.ok, "{msg}\n  validate() issues: {:?}", report.issues);
}

fn assert_not_opens_clean(bytes: &[u8], msg: &str) {
    let report = stemma::api::validate(bytes);
    assert!(!report.ok, "{msg}\n  validate() report: ok={}", report.ok);
}

fn accepted_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn rejected_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

