#[test]
fn para_mark_rprchange_reject_restores_prior_mark_props() {
    // ECMA-376 §17.13.5.30, ISO 29500-1 §17.13.5.30, §17.13.3.
    let body = r#"<w:p><w:pPr><w:rPr><w:b/><w:i/><w:rPrChange w:id="40" w:author="John Doe" w:date="2006-01-01T12:00:00Z"><w:rPr><w:i/></w:rPr></w:rPrChange></w:rPr></w:pPr><w:r><w:t>Example</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "para_mark_rprchange_reject_restores_prior_mark_props — ECMA-376 §17.13.5.30: \
         CT_ParaRPrChange inside pPr/rPr with a complete prior snapshot is schema-valid and must open without repair.",
    );
    assert_eq!(
        accepted_text(&b),
        "Example",
        "para_mark_rprchange_reject_restores_prior_mark_props — ECMA-376 §17.13.3, §17.13.5.30: \
         a paragraph-mark rPrChange is a property annotation carrying no character content; accepted text is unchanged."
    );
    assert_eq!(
        rejected_text(&b),
        "Example",
        "para_mark_rprchange_reject_restores_prior_mark_props — ECMA-376 §17.13.3, §17.13.5.30: \
         mark-only formatting reverts on reject but the run text never changes."
    );
    assert!(
        reserialize(&b).contains("<w:rPrChange"),
        "para_mark_rprchange_reject_restores_prior_mark_props — ECMA-376 §17.13.5.30: \
         verbatim/round-trip preservation must keep the paragraph-mark rPrChange record inside pPr/rPr. \
         Expected XML to contain <w:rPrChange"
    );
}

#[test]
fn rprchange_reject_restores_removed_prior_bold() {
    // ECMA-376 §17.13.5.31, ISO 29500-1 §17.13.5.31, §17.13.3.
    let body = r#"<w:p><w:r><w:rPr><w:rPrChange w:id="41" w:author="John Doe" w:date="2006-01-01T12:00:00Z"><w:rPr><w:b/></w:rPr></w:rPrChange></w:rPr><w:t>Example</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "rprchange_reject_restores_removed_prior_bold — ECMA-376 §17.13.5.31: \
         an rPrChange whose current rPr has only the trailing rPrChange and a non-null prior snapshot is schema-valid (CT_RPrChange).",
    );
    assert_eq!(
        accepted_text(&b),
        "Example",
        "rprchange_reject_restores_removed_prior_bold — ECMA-376 §17.13.3, §17.13.5.31: \
         accepting a run-property revision keeps the current (non-bold) formatting and changes no character content."
    );
    assert_eq!(
        rejected_text(&b),
        "Example",
        "rprchange_reject_restores_removed_prior_bold — ECMA-376 §17.13.3, §17.13.5.31: \
         rejecting restores the prior bold but the run text is unchanged because the annotation carries no characters."
    );
}

