    let body = r#"<w:p><w:r><w:rPr><w:rPrChange w:id="7" w:author="A" w:date="2024-01-01T00:00:00Z"><w:rPr><w:i/></w:rPr></w:rPrChange></w:rPr><w:t>Plain</w:t></w:r></w:p><w:sectPr/>"#;
