#[test]
fn prchange_track_attrs_id_author_preserved_roundtrip() {
    // ECMA-376 §A.1 CT_Markup (id required), CT_TrackChange (author required); ISO 29500-1 §17.13.5.29.
    let body = r#"<w:p><w:pPr><w:jc w:val="center"/><w:pPrChange w:id="9" w:author="John Doe" w:date="2006-01-01T12:00:00Z"><w:pPr/></w:pPrChange></w:pPr><w:r><w:t>Centered</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "prchange_track_attrs_id_author_preserved_roundtrip — ECMA-376 §A.1 CT_Markup/CT_TrackChange: \
         a pPrChange carrying required w:id and w:author is schema-conformant; Word opens without repair so stemma must report no errors.",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:id="9""#),
        "prchange_track_attrs_id_author_preserved_roundtrip — ECMA-376 §A.1 CT_Markup (id use=required): \
         stemma must preserve the required w:id verbatim across round-trip. Expected XML to contain w:id=\"9\"\n  XML: {xml}"
    );
    assert!(
        xml.contains(r#"w:author="John Doe""#),
        "prchange_track_attrs_id_author_preserved_roundtrip — ECMA-376 §A.1 CT_TrackChange (author use=required): \
         stemma must preserve the required w:author verbatim across round-trip. Expected XML to contain w:author=\"John Doe\"\n  XML: {xml}"
    );
}

#[test]
fn rprchange_serializes_as_trailing_rpr_child_after_edit_reemit() {
    // ECMA-376 §17.13.5.31, §A.1 CT_RPr, ISO 29500-1 §17.13.3.
    // NOTE: the spec gives this as `xmlRegex`. The `regex` crate is not a
    // dev-dependency, so each regex is translated to an ordered-/contains check
    // on whitespace-normalized XML (`norm_xml`), which is equivalent here:
    //   "<w:rPr>\s*<w:b/>\s*<w:rPrChange\b"  -> ordered: <w:rPr> , <w:b/> , <w:rPrChange
    //   "</w:rPrChange>\s*</w:rPr>"          -> contains "</w:rPrChange></w:rPr>"
    let body = r#"<w:p><w:r><w:rPr><w:b/><w:rPrChange w:id="5" w:author="A" w:date="2006-01-01T12:00:00Z"><w:rPr><w:i/></w:rPr></w:rPrChange></w:rPr><w:t>Example</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = norm_xml(&reserialize(&b));

    contains_in_order(&xml, &["<w:rPr>", "<w:b/>", "<w:rPrChange"]).unwrap_or_else(|e| {
        panic!(
            "rprchange_serializes_as_trailing_rpr_child_after_edit_reemit — ECMA-376 §17.13.3, §A.1 CT_RPr: \
             current run prop <w:b/> must precede rPrChange inside rPr (rPrChange is the trailing particle). {e}\n  XML: {xml}"
        )
    });
    assert!(
        xml.contains("</w:rPrChange></w:rPr>"),
        "rprchange_serializes_as_trailing_rpr_child_after_edit_reemit — ECMA-376 §A.1 CT_RPr: \
         rPrChange is the LAST child of rPr; rPr must close immediately after </w:rPrChange>. \
         Expected normalized XML to contain </w:rPrChange></w:rPr>\n  XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "rprchange_serializes_as_trailing_rpr_child_after_edit_reemit — ECMA-376 §17.13.5.31: \
         schema-correct CT_RPr ordering with a complete prior snapshot opens without repair.",
    );
}

