#[test]
fn sectprchange_prior_sectpr_optional_opens_clean() {
    // ECMA-376 §17.13.5.32, §A.1 CT_SectPrChange (inner sectPr minOccurs=0), ISO 29500-1 §17.13.5.32.
    let body = r#"<w:p><w:r><w:t>Body text.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:sectPrChange w:id="7" w:author="John Doe" w:date="2006-01-01T12:00:00Z"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "sectprchange_prior_sectpr_optional_opens_clean — ECMA-376 §17.13.5.32, §A.1 CT_SectPrChange: \
         the inner sectPr is minOccurs=0, so a sectPrChange with no prior-sectPr child is schema-valid; Word opens it without repair, so stemma's validator must report no errors.",
    );
}
